import Link from './Link'

const Animations = () => (
    <div>
        <h2>Animations</h2>
        <ol>
           {animations.map(({ link, title })=><Link link={link} title={title}/>)}
        </ol>
    </div>
)

const animations = [
    {
        title: "AnimateBig (Childhood animation channel)",
        link: "https://www.youtube.com/user/animatebig/videos"
    },
    {
        title: "Animation done for Dude (Coffee shop animation)",
        link: "https://www.youtube.com/watch?v=blNn2rKyjA0"
    }
]

export default Animations
